import{_ as l,o as e,c as t,a2 as i}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 快速升級練等攻略：從菜鳥到大師","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/fast-leveling.md","filePath":"bannerlord/fast-leveling.md"}'),r={name:"bannerlord/fast-leveling.md"};function h(o,a,d,n,u,s){return e(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="騎砍2-快速升級練等攻略-從菜鳥到大師" tabindex="-1">騎砍2 | 快速升級練等攻略：從菜鳥到大師 <a class="header-anchor" href="#騎砍2-快速升級練等攻略-從菜鳥到大師" aria-label="Permalink to &quot;騎砍2 | 快速升級練等攻略：從菜鳥到大師&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>騎砍2的技能難練是出了名的。弓箭練到 200 可能要射幾千支箭。這篇教你合法加速升級，不靠作弊也能快速成型。</p><hr><h2 id="一、技能升級原理" tabindex="-1">一、技能升級原理 <a class="header-anchor" href="#一、技能升級原理" aria-label="Permalink to &quot;一、技能升級原理&quot;">​</a></h2><p>每個技能都有學習率和學習上限。</p><ul><li>學習率 = 你點了幾點屬性（活力、控制等）× 專精點數</li><li>學習上限 = 決定這個技能最高能升到幾級</li><li>技能練到學習上限後，經驗條會變紅（升很慢）</li></ul><hr><h2 id="二、各技能速練法" tabindex="-1">二、各技能速練法 <a class="header-anchor" href="#二、各技能速練法" aria-label="Permalink to &quot;二、各技能速練法&quot;">​</a></h2><h3 id="單手-雙手-長桿" tabindex="-1">單手/雙手/長桿 <a class="header-anchor" href="#單手-雙手-長桿" aria-label="Permalink to &quot;單手/雙手/長桿&quot;">​</a></h3><ul><li>打競技場（最安全）</li><li>打劫匪（真刀真槍）</li><li>騎馬砍殺：騎馬時傷害更高 = 經驗更多</li></ul><h3 id="弓箭" tabindex="-1">弓箭 <a class="header-anchor" href="#弓箭" aria-label="Permalink to &quot;弓箭&quot;">​</a></h3><ul><li>打競技場弓箭模式</li><li>打劫匪時站在遠處射</li><li>攻城戰時站城下射城牆守軍（無限靶子）</li></ul><h3 id="騎術" tabindex="-1">騎術 <a class="header-anchor" href="#騎術" aria-label="Permalink to &quot;騎術&quot;">​</a></h3><ul><li>騎馬時造成的傷害全部算騎術經驗</li><li>騎馬砍人 = 同時練武器 + 騎術</li></ul><h3 id="交易" tabindex="-1">交易 <a class="header-anchor" href="#交易" aria-label="Permalink to &quot;交易&quot;">​</a></h3><ul><li>跑商買低賣高</li><li>每次交易有利潤就加經驗</li><li>戰利品賣掉也算（但要有利潤）</li></ul><h3 id="鍛造" tabindex="-1">鍛造 <a class="header-anchor" href="#鍛造" aria-label="Permalink to &quot;鍛造&quot;">​</a></h3><ul><li>熔煉武器 &gt; 鍛造武器（經驗差很多）</li><li>把所有戰利品拿去熔</li></ul><h3 id="領導力" tabindex="-1">領導力 <a class="header-anchor" href="#領導力" aria-label="Permalink to &quot;領導力&quot;">​</a></h3><ul><li>帶領部隊（帶越多升越快）</li><li>保持士氣高（食物多樣性）</li><li>帶領部隊打勝仗</li></ul><h3 id="管理學" tabindex="-1">管理學 <a class="header-anchor" href="#管理學" aria-label="Permalink to &quot;管理學&quot;">​</a></h3><ul><li>當軍需官（給同伴當）</li><li>管理城鎮</li></ul><hr><h2 id="三、加速技巧" tabindex="-1">三、加速技巧 <a class="header-anchor" href="#三、加速技巧" aria-label="Permalink to &quot;三、加速技巧&quot;">​</a></h2><h3 id="_3-1-專注而不是分散" tabindex="-1">3.1 專注而不是分散 <a class="header-anchor" href="#_3-1-專注而不是分散" aria-label="Permalink to &quot;3.1 專注而不是分散&quot;">​</a></h3><p>一次集中練 2-3 個技能，不要什麼都想練。技能專精點有限。</p><h3 id="_3-2-利用同伴" tabindex="-1">3.2 利用同伴 <a class="header-anchor" href="#_3-2-利用同伴" aria-label="Permalink to &quot;3.2 利用同伴&quot;">​</a></h3><p>讓同伴負責你不練的技能：</p><ul><li>同伴當軍需官 → 你不用練管理學</li><li>同伴當外科醫生 → 你不用練醫學</li><li>同伴當斥候 → 你不用練偵查</li></ul><h3 id="_3-3-裝-mod-加速" tabindex="-1">3.3 裝 MOD 加速 <a class="header-anchor" href="#_3-3-裝-mod-加速" aria-label="Permalink to &quot;3.3 裝 MOD 加速&quot;">​</a></h3><p>不想農？這些 MOD 合法加速：</p><ul><li>Attribute Per Level：每次升級多給屬性點</li><li>經驗倍率調整 MOD</li></ul><hr><h2 id="四、屬性點規劃" tabindex="-1">四、屬性點規劃 <a class="header-anchor" href="#四、屬性點規劃" aria-label="Permalink to &quot;四、屬性點規劃&quot;">​</a></h2><table tabindex="0"><thead><tr><th>遊戲階段</th><th style="text-align:center;">建議總屬性</th><th>重點技能</th></tr></thead><tbody><tr><td>前期（0-10 級）</td><td style="text-align:center;">活力 2 / 耐力 2 / 社交 2</td><td>單手、騎術、交易</td></tr><tr><td>中期（10-20 級）</td><td style="text-align:center;">加上智力 2</td><td>領導力、管理學</td></tr><tr><td>後期（20 級+）</td><td style="text-align:center;">補控制、狡詐</td><td>弓箭、偵查</td></tr></tbody></table><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./beginner-guide.html">騎砍2 | 新手求生指南</a></li><li><a href="./companions.html">騎砍2 | 夥伴全指南</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',45)])])}const q=l(r,[["render",h]]);export{b as __pageData,q as default};
